// ===== GOOGLE FLIGHTS SCRAPER VIA SCRAPERAPI =====
// Genera URLs, scrappea via ScraperAPI, parsea resultados

const config = $input.first().json;
const SCRAPER_API_KEY = config.scraperApiKey;

if (!SCRAPER_API_KEY) {
  return [{ json: { error: 'SCRAPER_API_KEY not configured', outbound: [], returns: [], roundtrips: [] } }];
}

// --- Configuración de rutas ---
const ORIGINS = ['MID', 'CUN'];
const DESTINATIONS = ['FCO', 'FLR', 'PSA', 'MXP', 'CDG', 'ORY'];
const RETURN_ORIGINS = ['FCO', 'FLR', 'PSA', 'MXP', 'BGY', 'NAP', 'VCE'];
const OUTBOUND_DATES = ['2026-09-24', '2026-09-25', '2026-09-26', '2026-09-27'];
const RETURN_DATES = ['2026-10-12', '2026-10-13', '2026-10-14'];
const RT_OUTBOUND = '2026-09-25';
const RT_RETURN = '2026-10-12';

// --- Protobuf encoder ---
function encodeVarint(value) {
  const bytes = [];
  let v = value >>> 0;
  if (v === 0) return [0];
  while (v > 0) {
    if (v > 0x7f) { bytes.push((v & 0x7f) | 0x80); v >>>= 7; }
    else { bytes.push(v & 0x7f); v = 0; }
  }
  return bytes;
}

function encodeVarintField(fn, val) { return [...encodeVarint((fn << 3) | 0), ...encodeVarint(val)]; }
function encodeLenDelim(fn, data) { const tag = encodeVarint((fn << 3) | 2); return [...tag, ...encodeVarint(data.length), ...data]; }
function encodeStrField(fn, str) { const enc = Array.from(Buffer.from(str)); return encodeLenDelim(fn, enc); }
function encodeAirport(fn, code) { return encodeLenDelim(fn, [...encodeVarintField(1, 1), ...encodeStrField(2, code)]); }

function buildTfs(tripType, legs) {
  let b = [...encodeVarintField(1, 28), ...encodeVarintField(2, tripType)];
  for (const leg of legs) {
    let lb = [...encodeStrField(2, leg.date)];
    for (const o of [].concat(leg.origins)) lb.push(...encodeAirport(13, o));
    for (const d of [].concat(leg.destinations)) lb.push(...encodeAirport(14, d));
    b.push(...encodeLenDelim(3, lb));
  }
  b.push(...encodeVarintField(8, 1), ...encodeVarintField(9, 1), ...encodeVarintField(14, 1));
  b.push(...encodeLenDelim(16, [0x08, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0x01]));
  b.push(...encodeVarintField(19, 1));
  return Buffer.from(b).toString('base64').replace(/\+/g, '-').replace(/\//g, '_').replace(/=+$/, '');
}

// --- Generar búsquedas ---
const searches = [];
for (const origin of ORIGINS) {
  for (const date of OUTBOUND_DATES) {
    searches.push({ type: 'outbound', tfs: buildTfs(2, [{ date, origins: origin, destinations: DESTINATIONS }]) });
  }
}
for (const dest of ORIGINS) {
  for (const date of RETURN_DATES) {
    searches.push({ type: 'return', tfs: buildTfs(2, [{ date, origins: RETURN_ORIGINS, destinations: dest }]) });
  }
}
for (const origin of ORIGINS) {
  searches.push({ type: 'roundtrip', tfs: buildTfs(1, [
    { date: RT_OUTBOUND, origins: origin, destinations: DESTINATIONS },
    { date: RT_RETURN, origins: DESTINATIONS, destinations: origin }
  ])});
}

// --- Parser de HTML ---
const KNOWN = new Set(['MID','CUN','FCO','FLR','PSA','MXP','CDG','ORY','BGY','NAP','VCE','MEX','DFW','IAH','ATL','JFK','LAX','ORD','MIA','AMS','MAD','BCN','LHR','FRA','IST']);
const EXCLUDE = new Set(['USD','MXN','EUR','AND','THE','FOR','NOT','ALL','HRS','MIN','VIA','DAY','SEP','OCT','NOV','MON','TUE','WED','THU','FRI','SAT','SUN']);

function parseFlights(html) {
  const flights = [];
  const seen = new Set();

  // Extract price matches with surrounding context
  const priceRegex = /(?:US)?\$([\d,]+)/g;
  let match;
  while ((match = priceRegex.exec(html)) !== null) {
    const price = parseInt(match[1].replace(/,/g, ''));
    if (price < 80 || price > 50000) continue;

    // Get context around the price (500 chars before and after)
    const start = Math.max(0, match.index - 500);
    const end = Math.min(html.length, match.index + 500);
    const context = html.substring(start, end);

    // Extract airport codes from context
    const codes = (context.match(/\b[A-Z]{3}\b/g) || []).filter(c => KNOWN.has(c) && !EXCLUDE.has(c));
    if (codes.length < 2) continue;

    const from = codes[0];
    const to = codes[1];
    const key = `${from}-${to}-${price}`;
    if (seen.has(key)) continue;
    seen.add(key);

    // Duration
    const durMatch = context.match(/(\d+)\s*(?:hr?|h)(?:\s*(\d+)\s*(?:min|m))?/i);
    const durationH = durMatch ? parseInt(durMatch[1]) + (parseInt(durMatch[2] || '0') / 60) : 0;

    // Stops
    const stopsMatch = context.match(/(\d+)\s*(?:stop|escala)/i);
    const stops = stopsMatch ? parseInt(stopsMatch[1]) : 0;

    flights.push({
      from, to,
      airlines: 'Via Google Flights',
      price_usd: price,
      departure: '',
      arrival: '',
      stops,
      duration_h: Math.round(durationH * 10) / 10,
      deep_link: `https://www.google.com/travel/flights?q=flights+from+${from}+to+${to}`,
    });
  }

  return flights;
}

// --- Ejecutar scraping ---
const allOutbound = [];
const allReturns = [];
const allRoundtrips = [];
const errors = [];

for (let i = 0; i < searches.length; i++) {
  const s = searches[i];
  const gfUrl = `https://www.google.com/travel/flights/search?tfs=${s.tfs}&curr=USD&hl=es&gl=mx`;
  const scraperUrl = `http://api.scraperapi.com?api_key=${SCRAPER_API_KEY}&url=${encodeURIComponent(gfUrl)}&render=true&country_code=mx&device_type=desktop`;

  try {
    const html = await $helpers.httpRequest({ method: 'GET', url: scraperUrl, timeout: 60000 });
    const flights = parseFlights(typeof html === 'string' ? html : JSON.stringify(html));

    if (s.type === 'outbound') allOutbound.push(...flights);
    else if (s.type === 'return') allReturns.push(...flights);
    else {
      for (const f of flights) f.type = 'roundtrip';
      allRoundtrips.push(...flights);
    }
  } catch (err) {
    errors.push(`${s.type}: ${err.message}`);
  }

  // Rate limiting
  if (i < searches.length - 1) {
    await new Promise(r => setTimeout(r, 4000));
  }
}

// --- Deduplicar ---
function dedup(flights) {
  const m = new Map();
  for (const f of flights) {
    const k = `${f.from}-${f.to}-${f.airlines}-${f.price_usd}`;
    if (!m.has(k) || f.price_usd < m.get(k).price_usd) m.set(k, f);
  }
  return [...m.values()].sort((a, b) => a.price_usd - b.price_usd);
}

return [{
  json: {
    outbound: dedup(allOutbound).slice(0, 15),
    returns: dedup(allReturns).slice(0, 15),
    roundtrips: dedup(allRoundtrips).slice(0, 10),
    _meta: {
      scraped_at: new Date().toISOString(),
      total_searches: searches.length,
      errors: errors.length ? errors : undefined
    }
  }
}];
